import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class Encrypter {
    private Map<Character, String> encryptMap;
    private Map<String, Character> decryptMap;
    private Set<String> dictionary;

    public Encrypter(char[] keys, String[] values, String[] dictionary) {
        encryptMap = new HashMap<>();
        decryptMap = new HashMap<>();
        this.dictionary = new HashSet<>();
        for (int i = 0; i < keys.length; i++) {
            encryptMap.put(keys[i], values[i]);
            decryptMap.put(values[i], keys[i]);
        }
        for (String word : dictionary) {
            this.dictionary.add(word);
        }
    }

    public String encrypt(String original) {
        StringBuilder res = new StringBuilder();
        for (char c : original.toCharArray()) {
            if (!encryptMap.containsKey(c)) {
                return "";
            }
            res.append(encryptMap.get(c));
        }
        return res.toString();
    }

    public String decrypt(String encrypted) {
        StringBuilder res = new StringBuilder();
        for (int i = 0; i < encrypted.length(); i += 2) {
            String temp = encrypted.substring(i, i + 2);
            if (!decryptMap.containsKey(temp)) {
                return "";
            }
            res.append(decryptMap.get(temp));
        }
        String decrypted = res.toString();
        if (!dictionary.contains(decrypted)) {
            return "";
        }
        return decrypted;
    }
}
```

